import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if len(unvisited_customers) == 0:
        return None

    def distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    # Calculate distances from current truck position to each unvisited customer
    distances = np.array([distance(cur_truck_pos, customer) for customer in unvisited_customers])

    # Estimate remaining workload for each truck
    truck_loads = []
    for truck_pos in all_truck_pos:
        truck_load = sum([distance(truck_pos, customer) for customer in unvisited_customers])
        truck_loads.append(truck_load)

    average_load = np.mean(truck_loads)

    # Prioritize the closest customer if the truck's current load is above average
    if sum([distance(cur_truck_pos, customer) for customer in unvisited_customers]) > average_load:
        best_node = np.argmin(distances)
    else:
        # Else, wait if dynamically adding new customers is anticipated
        if np.random.rand() > 0.8:  # Assuming some threshold to induce wait dynamically
            return None
        best_node = np.argmin(distances)

    return best_node
